export function initResourcePicker(root: ParentNode = document) {
  const picker = root.querySelector<HTMLElement>('[data-resource-picker]');
  const detail = root.querySelector<HTMLElement>('[data-resource-detail]');
  if (!picker || !detail) return;
  const detailEl = detail;

  const tokens = Array.from(picker.querySelectorAll<HTMLButtonElement>('[data-resource-token]'));
  const title = detail.querySelector<HTMLElement>('[data-resource-title]');
  const kicker = detail.querySelector<HTMLElement>('[data-resource-kicker]');
  const replaces = detail.querySelector<HTMLElement>('[data-resource-replaces]');
  const use = detail.querySelector<HTMLElement>('[data-resource-use]');
  const priority = detail.querySelector<HTMLElement>('[data-resource-priority]');

  function select(token: HTMLButtonElement) {
    tokens.forEach((item) => {
      const active = item === token;
      item.classList.toggle('active', active);
      item.setAttribute('aria-pressed', String(active));
    });

    if (title) title.textContent = token.dataset.title ?? '';
    if (kicker) kicker.textContent = token.dataset.kicker ?? '';
    if (replaces) replaces.textContent = token.dataset.replaces ?? '';
    if (use) use.textContent = token.dataset.use ?? '';
    if (priority) priority.textContent = token.dataset.priority ?? '';

    detailEl.classList.remove('resource-detail-pop');
    window.requestAnimationFrame(() => detailEl.classList.add('resource-detail-pop'));
  }

  tokens.forEach((token) => {
    token.addEventListener('click', () => select(token));
  });
}
