const STORAGE_PREFIX = 'lws5_';

export function initChecklist(root: HTMLElement) {
  const rows = root.querySelectorAll<HTMLElement>('.checklist-row');
  const doneEl = root.querySelector<HTMLElement>('[data-cl-done]');
  const totalEl = root.querySelector<HTMLElement>('[data-cl-total]');
  const fillEl = root.querySelector<HTMLElement>('[data-cl-fill]');
  const pctEl = root.querySelector<HTMLElement>('[data-cl-pct]');

  const total = rows.length;
  if (totalEl) totalEl.textContent = String(total);

  function updateProgress() {
    const done = root.querySelectorAll<HTMLInputElement>('.checklist-row input:checked').length;
    if (doneEl) doneEl.textContent = String(done);
    if (pctEl) pctEl.textContent = total > 0 ? Math.round((done / total) * 100) + '%' : '0%';
    if (fillEl) fillEl.style.width = total > 0 ? `${(done / total) * 100}%` : '0%';
  }

  rows.forEach((row) => {
    const id = row.dataset.id;
    if (!id) return;
    const cb = row.querySelector<HTMLInputElement>('input[type=checkbox]');
    if (!cb) return;

    if (localStorage.getItem(STORAGE_PREFIX + id) === 'true') {
      cb.checked = true;
      row.classList.add('checked');
    }

    const toggle = () => {
      cb.checked = !cb.checked;
      persist(id, cb.checked, row);
      updateProgress();
    };
    row.addEventListener('click', (e) => {
      if (e.target === cb || (e.target as HTMLElement).tagName === 'LABEL') return;
      toggle();
    });
    cb.addEventListener('change', () => {
      persist(id, cb.checked, row);
      updateProgress();
    });
  });

  const resetBtn = root.querySelector<HTMLButtonElement>('#reset-checklist');
  if (resetBtn) {
    resetBtn.addEventListener('click', () => {
      rows.forEach((row) => {
        const id = row.dataset.id;
        const cb = row.querySelector<HTMLInputElement>('input[type=checkbox]');
        if (!cb || !id) return;
        cb.checked = false;
        row.classList.remove('checked');
        localStorage.removeItem(STORAGE_PREFIX + id);
      });
      updateProgress();
    });
  }

  updateProgress();
}

function persist(id: string, checked: boolean, row: HTMLElement) {
  row.classList.toggle('checked', checked);
  localStorage.setItem(STORAGE_PREFIX + id, String(checked));
}
